# Security: Whitelist of allowed classes for deserialization
ALLOWED_CLASSES = {
    'builtins.list',
    'builtins.dict',
    'builtins.str',
    'builtins.int',
    'builtins.float',
    'builtins.bool',
    'builtins.tuple',
    'builtins.set',
    'datetime.datetime',
    'datetime.date'
}

def is_safe_class(obj):
    """Check if the object's class is in the allowed list"""
    if hasattr(obj, '__class__'):
        class_name = f"{obj.__class__.__module__}.{obj.__class__.__name__}"
        return class_name in ALLOWED_CLASSES
    return True

def safe_pickle_loads(data):
    """Safely deserialize pickle data with security checks"""
    try:
        # Use pickle.loads with custom unpickler that validates classes
        obj = pickle.loads(data)
        
        # Validate that all objects in the structure are safe
        def validate_object(obj):
            if isinstance(obj, (list, tuple, set)):
                for item in obj:
                    validate_object(item)
            elif isinstance(obj, dict):
                for key, value in obj.items():
                    validate_object(key)
                    validate_object(value)
            else:
                if not is_safe_class(obj):
                    raise ValueError(f"Unsafe class detected: {type(obj)}")
        
        validate_object(obj)
        return obj
    except Exception as e:
        logger.error(f"Deserialization failed: {str(e)}")
        raise

